  import java.util.ArrayList;
  import sailpoint.object.Custom;
  import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
  
   /**
		 * List all Domains updated in custom object	
		 * @return list of all DOMAIN 
		 */
  static Log logger = LogFactory.getLog("rule.CreateContractor");
	logger.debug("Entering Domain AllowedValues Rule");
  
  ArrayList domainValues = new ArrayList();
  String ministries = "";
  Custom allowedValues = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");
	
  
  if(null != form.getField("ministry") && null != form.getField("ministry").getValue()){    
    ministries = form.getField("ministry").getValue();    
    if (allowedValues != null && null != allowedValues.get("Domain") && null != allowedValues.get("Domain").get(ministries)) {
      domainValues = allowedValues.get("Domain").get(ministries);  
      Collections.sort(domainValues);	  
    }
  }
  
  if(null != allowedValues){
  	//comment decache //context.decache(allowedValues);
  }
  
  logger.debug("Exiting Domain AllowedValues Rule");
  return domainValues;
